import React from 'react';
import { Menu } from 'antd';

const { SubMenu } = Menu;

const MenuBody = () => {
  return (
    <div className="MenuBody">
        <Menu mode="horizontal">
      <Menu.Item key="categories" title="Categories">
        <SubMenu key="sub1" title="Subcategory 1">
          <Menu.Item key="category1.1">Category 1.1</Menu.Item>
          <Menu.Item key="category1.2">Category 1.2</Menu.Item>
        </SubMenu>
        <SubMenu key="sub2" title="Subcategory 2">
          <Menu.Item key="category2.1">Category 2.1</Menu.Item>
          <Menu.Item key="category2.2">Category 2.2</Menu.Item>
        </SubMenu>
      </Menu.Item>
    </Menu>
    </div>

  );
};

export default MenuBody;
